-- ============================================================================
-- One-time data import: Stephanie's 2026 expenses, from STEPHANIE Expenses.pdf.
-- DATA only, not a schema change. Safe to re-run: deletes any prior run of this
-- exact script (matched by boat_id + a marker in notes) before re-inserting.
--
-- Excluded: one row dated 2 May 2025 ("prepayment for the bottles", EUR458.80) -
-- outside 2026, per "only from 2026" - not entered, not silently reconciled.
--
-- Flagged, not corrected: two rows are dated 30 Jun 2025 ("EFKA- May" and
-- "Nat- May 27.5-31.5.26") sitting among otherwise-2026 rows, and the second
-- one's own description names dates in 2026 - almost certainly a 2025/2026 typo
-- in the source sheet, but entered exactly as dated rather than silently
-- "fixed" - please check these two and correct the year in the app if needed.
--
-- The row dated 17 Apr 2026 with description "?" and no category in the source
-- sheet was entered as category "Other", description kept as "?" - not guessed.
-- ============================================================================

do $$
declare
  v_boat_id uuid;
  v_marker text := 'stephanie-expenses-2026-import';
begin
  select id into v_boat_id from public.boats where lower(trim(name)) = 'stephanie';
  if v_boat_id is null then
    raise exception 'Boat "Stephanie" not found (matched on lower(trim(name)) = ''stephanie'') - check the exact boat name in the boats table and adjust this script before running it.';
  end if;

  delete from public.expenses where boat_id = v_boat_id and notes = v_marker;

end $$;
